import{_ as t,o as a,c as i,ae as r}from"./chunks/framework.B6gjLfeO.js";const m=JSON.parse('{"title":"Fraud Analytics","description":"","frontmatter":{"title":"Fraud Analytics","slug":"fraud-analytics"},"headers":[],"relativePath":"marketer-hub/fraud-analytics.md","filePath":"marketer-hub/fraud-analytics.md"}'),s={name:"marketer-hub/fraud-analytics.md"};function o(n,e,l,c,d,h){return a(),i("div",null,[...e[0]||(e[0]=[r('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Branch’s Fraud Detection Platform uses an intelligent blocklist to block known bad actors in real time, ensuring customers don’t pay for fraudulent traffic. It includes core metrics that help identify forms of fraud such as install hijacking, click flooding and device reset fraud.</p><p>The platform leverages Branch’s persona data to give you RealScore - a model that intelligently scores the likelihood that any given install comes from a real person rather than a bot, malware or false attribution claim. RealScore depends on a variety of web and app signals to establish patterns of normal and fraudulent behavior, making it the first fraud detection product to leverage the full set of signals available on mobile.</p><div class="warning custom-block"><p class="custom-block-title">Warning</p><p>This article details the fraud analytics experience for the <a href="./branch-dashboard-overview.html">legacy Branch platform</a>, which is slated for deprecation. For more information on fraud analytics in the <a href="./new-branch-overview.html">new Branch platform</a>, visit our <a href="./analysis-dashboards.html">Analysis Dashboards</a> guide.</p></div><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>In order to view fraud analytics, you need to have completed the following:</p><ol><li><p><a href="./fraud-rules.html">Enabled Fraud Rules</a></p></li><li><p>Have sufficient <a href="./add-manage-users-roles-permissions-access.html">access/permission</a> rights for your Branch app.</p><ul><li><strong>View/Edit</strong> access to the <strong>Fraud Settings &amp; Data</strong> permission.</li></ul></li></ol><h2 id="core-metrics" tabindex="-1">Core Metrics <a class="header-anchor" href="#core-metrics" aria-label="Permalink to &quot;Core Metrics&quot;">​</a></h2><p>Core Metrics allow you to quickly analyze fraud detection performance.</p><table tabindex="0"><thead><tr><th>Metric</th><th>Description</th></tr></thead><tbody><tr><td>% Blocked Installs</td><td>The percentage of blocked installs divided by installs.</td></tr><tr><td>Click to Install %</td><td>The percentage of attributed installs divided by clicks.</td></tr><tr><td>Install % Over 1d</td><td>The percentage of unblocked installs where the time from click to install was over 1 day - an indicator of <strong>click flooding</strong>.</td></tr><tr><td>Install % Under 10s</td><td>The percentage of unblocked installs where the time from click to install was under 10 seconds - an indicator of <strong>click injection</strong></td></tr></tbody></table><h2 id="fraud-report" tabindex="-1">Fraud Report <a class="header-anchor" href="#fraud-report" aria-label="Permalink to &quot;Fraud Report&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">In-Depth Fraud &amp; Recommendations</p><p>Because Fraud Detection is very complex, visit our guide on understanding fraud and recommendations <a href="./in-depth-fraud-recommendations.html">here</a>.</p></div><p>The Fraud Report will measure the performance of your blocked events for specific fraud indicators. Branch recommends creating fraud rules to block erroneous attribution credit in real time.</p><h3 id="available-fraud-rules" tabindex="-1">Available Fraud Rules <a class="header-anchor" href="#available-fraud-rules" aria-label="Permalink to &quot;Available Fraud Rules&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Fraud Rule</th><th>Description</th></tr></thead><tbody><tr><td>Conversion Time</td><td>The time between the touch and the conversion is short.</td></tr><tr><td>Click Injection</td><td>Events with suspicious touch to Play Store Install Begin times, indicative of Click Injection.</td></tr><tr><td>Device Conflict</td><td>The device information on the touch and the conversion are different.</td></tr><tr><td>Geo Conflict</td><td>The touch and the conversion occur in different countries.</td></tr><tr><td>IP</td><td>Events coming from known TOR networks.</td></tr><tr><td>Once Ever Capped</td><td>Events only occurring once per user.</td></tr><tr><td>Persona Fraud</td><td>Browsers or devices with suspicious behavior based on Branch’s cross-platform <a href="./predictive-modeling.html">Link Graph</a>.</td></tr><tr><td>Suspicious Device</td><td>Install from fake devices or emulators.</td></tr><tr><td>Custom</td><td>Events matching your custom selection of fraud parameters.</td></tr><tr><td>None</td><td>Do not show blocked events based on Fraud Rules. Branch automatically selects <code>None</code> when you filter on Key Fraud Indicators instead.</td></tr></tbody></table><h3 id="key-fraud-indicators" tabindex="-1">Key Fraud Indicators <a class="header-anchor" href="#key-fraud-indicators" aria-label="Permalink to &quot;Key Fraud Indicators&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Fraud Indicator</th><th>Description</th></tr></thead><tbody><tr><td>Fake Devices/Click Farms</td><td>Emulators and click farms generate clicks from suspicious IPs, as well as show abnormal behavior after installing. Check blocked clicks and your user value metrics in Ads Analytics to identify this fraud.</td></tr><tr><td>Install Hijacking/Click Injection</td><td>When a new app is installed, other apps on the phone can sometimes detect the install, even before the first open. Fraudulent publishers may fire off a click when they detect an organic install, just before the app is opened. This can be identified by suspiciously low click to install times.</td></tr><tr><td>Click Flooding</td><td>Publishers can generate millions of clicks with different device IDs in the hope that one of those users will install later. Generally the click and installs actions are disconnected, so you can expect to see long click to install times and a very low conversion rate.</td></tr><tr><td>Ad Stacking</td><td>Publishers will sometimes put dozens of ads in one ad placement, causing high numbers of impressions and clicks, with low install rates.</td></tr><tr><td>Device Reset</td><td>Device reset fraud is characterized by new devices from suspicious IPs. Keep an eye on your user value metrics and suspiciously high click to install rates.</td></tr></tbody></table><h2 id="click-to-install-cti-time-chart" tabindex="-1">Click to Install (CTI) Time Chart <a class="header-anchor" href="#click-to-install-cti-time-chart" aria-label="Permalink to &quot;Click to Install (CTI) Time Chart&quot;">​</a></h2><p>The Click to Install (CTI) Time is a great tool for comparing CTI time for specific ad networks broken out by OS. Here you&#39;ll be able to compare CTI time in:</p><ul><li>seconds</li><li>minutes</li><li>hours</li><li>days</li></ul><h2 id="click-and-impression-abuse-thresholds" tabindex="-1">Click and impression abuse thresholds <a class="header-anchor" href="#click-and-impression-abuse-thresholds" aria-label="Permalink to &quot;Click and impression abuse thresholds&quot;">​</a></h2><h3 id="overview-1" tabindex="-1">Overview <a class="header-anchor" href="#overview-1" aria-label="Permalink to &quot;Overview&quot;">​</a></h3><p>This protective threshold protects against inhuman levels of illegitimate click and/or impression activity from a single ad network.</p><h5 id="how-it-works" tabindex="-1">How it works: <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works:&quot;">​</a></h5><p>For ad networks with low conversion rates and inhumanly high click/impression volumes, Branch will protect the account by blocking the ad network traffic for a period of 24 hours or more.</p><p>For this specific threshold, networks exceeding the click/impression abuse rate will have further clicks blocked for a 48-hour period and then reset. Branch will not report further excessive clicks for that period and those clicks/impressions will not be used for attribution.<br> The dynamic logic applied for this threshold accounts for multiple factors including conversion rate, click volume, impression volume, detected fraud rate, and geographic and industry benchmarks.</p><h3 id="faqs" tabindex="-1">FAQs <a class="header-anchor" href="#faqs" aria-label="Permalink to &quot;FAQs&quot;">​</a></h3><details><summary>Why not block only a portion of the traffic?</summary><p>There are several upstream measures to limit blocking to a limited set of devices and sub-sources from the network. This additional network-level measure only activates following cases where several upstream measures have been exceeded. This level of blocking is extremely rare and only occurs when a network is rotating several sources in high frequency, or not specifying sub-sources, and the vast majority are determined to be inhuman with excessive volume.</p></details><details><summary>How is the threshold determined?</summary><p>The threshold is dynamic and accounts for several factors including conversion rate, excessively high click/impression/impression volumes, and geographic and industry benchmarks. In general, this threshold is exceeded only rarely, and only under inhuman click/impression/impression abuse volume. It applies to a minute fraction of activity system-wide. We do not disclose further specifics on the logic to protect customers from attempted manipulation.</p></details><details><summary>How often will the temporary blocking be lifted or reset?</summary><p>The threshold is automatically reassessed every 48 hours. It is imperative that the click/impression/impression abuse subsides prior or it is possible that the block may be continued for another period. Once the temporary block is applied, it cannot be reset prior to the end of the active period.</p></details><details><summary>What happens if a network is flagged multiple times for abuse?</summary><p>Subsequent violations will be reviewed for potential removal and longer-term banning of the source.</p></details><details><summary>What if the click/impression/impression traffic is not considered as abusive by the client app?</summary><p>Media sources triggering this threshold violate Branch terms of system abuse. This abuse protection is an additional layer above and beyond other client fraud protections. For questions and concerns about this protective threshold, please contact your Branch Client Success Manager.</p></details><details><summary>What if the customer wishes for this traffic not to be blocked?</summary><p>While clients have direct control over fraud protection settings, the click and impression abuse thresholds cannot be bypassed. This abuse protection helps ensure reliability of the API and protects customers from heavy attack.</p></details><details><summary>What is the reason for this additional approach when there are more granular approaches?</summary><p>While there are several layers of fraud protection with fine-tuning, this is a broader “safety net” to protect from gross, extreme abuse of the system. In most cases, abuse is blocked at more granular levels, and in the case of an excessive abuse volume, this threshold protects the customer account.</p></details><details><summary>How can networks ensure not to be blocked during campaign launch &amp; optimization?</summary><p>Ensure that all click/impression activity is legitimate and is driving a conversion rate within normal expected tolerance. Conversion rates should be representative of what is typical for the app, given a genuine legitimate user-initiated click/impression of interest. If sending ad views as click/impressions, or if the audience conversion rate is several deviations outside of the normal range, this will fail the conversion rate criteria. If the campaign is also sending multiple millions of click/impressions daily, that is additionally figured as part of the criteria. The campaign should have normal tolerance rates for the geographic and industry benchmarks or may be temporarily blocked for excessive volume.</p></details><details><summary>How can networks check for problematic traffic and sub-sources?</summary><p>Using reporting, networks can monitor click/impression volumes and conversion rates by secondary_publisher source. Networks are encouraged to optimize away from sources that have excessively high click/impression volumes with uncommonly low conversion rates. If using sources with lower conversion rates, the activity must be within a reasonable tolerance. It is a violation of Branch terms to send abuse level volume.</p></details>',36)])])}const p=t(s,[["render",o]]);export{m as __pageData,p as default};
